import express from 'express';
import path from 'path';
import fs from 'fs';
import { createServer as createViteServer } from 'vite';
import { initializeApp } from 'firebase/app';
import { 
  getFirestore, 
  collection, 
  getDocs, 
  getDoc, 
  addDoc, 
  doc, 
  updateDoc, 
  deleteDoc 
} from 'firebase/firestore';

// Load Firebase Config dynamically
const configPath = path.join(process.cwd(), 'firebase-applet-config.json');
let firebaseConfig: any = {};
try {
  firebaseConfig = JSON.parse(fs.readFileSync(configPath, 'utf-8'));
} catch (err) {
  console.error('Failed to load firebase-applet-config.json:', err);
}

// Initialize Firebase App & Firestore
const firebaseApp = initializeApp({
  apiKey: firebaseConfig.apiKey,
  authDomain: firebaseConfig.authDomain,
  projectId: firebaseConfig.projectId,
  storageBucket: firebaseConfig.storageBucket,
  messagingSenderId: firebaseConfig.messagingSenderId,
  appId: firebaseConfig.appId
});

const db = getFirestore(firebaseApp, firebaseConfig.firestoreDatabaseId || "ai-studio-7a5f04d9-280b-4053-89bf-50d1530d6608");

async function startServer() {
  const app = express();
  const PORT = 3000;

  // Middleware for parsing requests
  app.use(express.json({ limit: '10mb' }));

  // API Route: GET all documents from a collection
  app.get('/api/db/:collectionName', async (req, res) => {
    try {
      const { collectionName } = req.params;
      const colRef = collection(db, collectionName);
      const snapshot = await getDocs(colRef);
      const items = snapshot.docs.map(docSnapshot => ({
        id: docSnapshot.id,
        ...docSnapshot.data()
      }));
      res.json(items);
    } catch (error: any) {
      console.error(`Error fetching collection ${req.params.collectionName}:`, error);
      res.status(500).json({ error: error.message || String(error) });
    }
  });

  // API Route: GET a single document by ID
  app.get('/api/db/:collectionName/:id', async (req, res) => {
    try {
      const { collectionName, id } = req.params;
      const docRef = doc(db, collectionName, id);
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) {
        res.json({ id: docSnap.id, ...docSnap.data() });
      } else {
        res.status(404).json({ error: 'Document not found' });
      }
    } catch (error: any) {
      console.error(`Error getting document ${req.params.id} from ${req.params.collectionName}:`, error);
      res.status(500).json({ error: error.message || String(error) });
    }
  });

  // API Route: POST (add a new document)
  app.post('/api/db/:collectionName', async (req, res) => {
    try {
      const { collectionName } = req.params;
      const colRef = collection(db, collectionName);
      const docRef = await addDoc(colRef, req.body);
      res.json({ id: docRef.id });
    } catch (error: any) {
      console.error(`Error adding document to collection ${req.params.collectionName}:`, error);
      res.status(500).json({ error: error.message || String(error) });
    }
  });

  // API Route: PUT (update an existing document)
  app.put('/api/db/:collectionName/:id', async (req, res) => {
    try {
      const { collectionName, id } = req.params;
      const docRef = doc(db, collectionName, id);
      await updateDoc(docRef, req.body);
      res.json({ id });
    } catch (error: any) {
      console.error(`Error updating document ${req.params.id} in collection ${req.params.collectionName}:`, error);
      res.status(500).json({ error: error.message || String(error) });
    }
  });

  // API Route: DELETE a document
  app.delete('/api/db/:collectionName/:id', async (req, res) => {
    try {
      const { collectionName, id } = req.params;
      const docRef = doc(db, collectionName, id);
      await deleteDoc(docRef);
      res.json({ id });
    } catch (error: any) {
      console.error(`Error deleting document ${req.params.id} from collection ${req.params.collectionName}:`, error);
      res.status(500).json({ error: error.message || String(error) });
    }
  });

  // Vite middleware for development or serving compiled client files
  if (process.env.NODE_ENV !== 'production') {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: 'spa',
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, '0.0.0.0', () => {
    console.log(`[Server] Full-stack backend proxy running on http://0.0.0.0:${PORT}`);
  });
}

startServer();
